import subprocess
import shlex

def executeCommand():
    allowed_commands = ['ls', 'pwd', 'date', 'whoami']
    user_input = input("Enter command: ")
    parts = shlex.split(user_input)
    if not parts:
        return
    if parts[0] not in allowed_commands:
        print("Invalid command")
        return
    if len(parts) > 1:
        print("Invalid command: arguments not allowed")
        return
    try:
        subprocess.run(parts, check=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
    except subprocess.CalledProcessError as e:
        print(f"Error: {e}")

