def checkAdminPassword(password):
    common_passwords = {'password', '123456', 'admin', '123456789', 'qwerty', 'letmein', '12345678', '12345', '000000', '111111'}
    if password in common_passwords:
        return False
    if ' ' in password:
        return False
    if len(password) < 12:
        return False
    if not any(c.isupper() for c in password):
        return False
    if not any(c.islower() for c in password):
        return False
    if not any(c.isdigit() for c in password):
        return False
    special_chars = '!@#$%^&*()_+-=[]{}|;:,.<>?/'
    if not any(c in special_chars for c in password):
        return False
    return True

